fetch('https://www.e-solat.gov.my/index.php?r=esolatApi/takwimsolat&period=today&zone=SGR01').then(function(r){return r.json()}).then(function(data){var t=data.prayerTime[0];var f=function(s){return s.substring(0,5)};document.getElementById('solatBanner').innerHTML='<div class="solatBanner-inner"><span class="solatBanner-title">Waktu Solat: Selangor \u2014 '+t.date+'</span><span>Imsak<br>'+f(t.imsak)+'</span><span>Subuh<br>'+f(t.fajr)+'</span><span>Syuruk<br>'+f(t.syuruk)+'</span><span>Dhuha<br>'+f(t.dhuha)+'</span><span>Zohor<br>'+f(t.dhuhr)+'</span><span>Asar<br>'+f(t.asr)+'</span><span>Maghrib<br>'+f(t.maghrib)+'</span><span>Isyak<br>'+f(t.isha)+'</span></div>'});